CREATE DATABASE IF NOT EXISTS dairy_db CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;\nUSE dairy_db;\nCREATE TABLE IF NOT EXISTS users (id INT AUTO_INCREMENT PRIMARY KEY, username VARCHAR(100) UNIQUE NOT NULL, password VARCHAR(255) NOT NULL, role ENUM('admin','user') NOT NULL DEFAULT 'user', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);\nCREATE TABLE IF NOT EXISTS bills (id INT AUTO_INCREMENT PRIMARY KEY, user_id INT NOT NULL, invoice VARCHAR(80), bill_date DATE, customer VARCHAR(150), shop_name VARCHAR(150), shop_id VARCHAR(60), discount DECIMAL(8,2), tax DECIMAL(8,2), total DECIMAL(12,2), items TEXT, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE);